// intStr renders an optional integer measurement with its unit, or "unknown"
// when the value is absent (nil). A safety tool must not print a fabricated 0
// as if it were a real reading, so an absent intensity/pressure reads as
// "unknown" rather than "0 kt".
func intStr(p *int, unit string) string {
	if p == nil {
		return "unknown"
	}
	return fmt.Sprintf("%d %s", *p, unit)
}

// renderStormHuman renders a compact human view of a storm detail, always
// surfacing the headline facts (name + classification + forecast cone URL).
func renderStormHuman(d *stormDetail) string {
	var b strings.Builder
	fmt.Fprintf(&b, "%s (%s): %s\n", d.Name, d.ID, d.Classification)
	fmt.Fprintf(&b, "  intensity   %s\n", intStr(d.IntensityKt, "kt"))
	fmt.Fprintf(&b, "  pressure    %s\n", intStr(d.PressureMb, "mb"))
	fmt.Fprintf(&b, "  location    %s %s (%.1f, %.1f)\n", d.Latitude, d.Longitude, d.Lat, d.Lon)
	fmt.Fprintf(&b, "  movement    %d deg at %d kt\n", d.MovementDir, d.MovementSpeed)
	fmt.Fprintf(&b, "  updated     %s\n", d.LastUpdate)
	if d.Products.PublicAdvisory != nil {
		fmt.Fprintf(&b, "  public adv  %s\n", d.Products.PublicAdvisory.URL)
	}
	if d.GIS.TrackCone != nil && d.GIS.TrackCone.Kmz != "" {
		fmt.Fprintf(&b, "  cone        %s\n", d.GIS.TrackCone.Kmz)
	}
	return b.String()
}

